INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('this', 'op', 56, 'OP', '这个；这；当前的', 'point to a near thing, idea, or time', 'This question is not hard.', '这个问题不难。', '[{"w":"that","def":"that: 相关的动作或关系词","vs":"与 this 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"that\" / \"this\" 的替换练习"},{"w":"I","def":"I: 可帮助扩展句型的基础词","vs":"与 this 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"I\" / \"this\" 的替换练习"},{"w":"he","def":"he: 同一组 Basic English 操作词","vs":"与 this 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"he\" / \"this\" 的替换练习"}]'),
  ('I', 'op', 57, 'OP', '我；说话者自己', 'the person who is speaking or writing', 'I have a letter for you.', '我有一封给你的信。', '[{"w":"this","def":"this: 相关的动作或关系词","vs":"与 I 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"this\" / \"I\" 的替换练习"},{"w":"he","def":"he: 可帮助扩展句型的基础词","vs":"与 I 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"he\" / \"I\" 的替换练习"},{"w":"you","def":"you: 同一组 Basic English 操作词","vs":"与 I 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"you\" / \"I\" 的替换练习"}]'),
  ('he', 'op', 58, 'OP', '他；男性第三人称', 'a male person already known or mentioned', 'He will take the train tomorrow.', '他明天会坐火车。', '[{"w":"I","def":"I: 相关的动作或关系词","vs":"与 he 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"I\" / \"he\" 的替换练习"},{"w":"you","def":"you: 可帮助扩展句型的基础词","vs":"与 he 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"you\" / \"he\" 的替换练习"},{"w":"who","def":"who: 同一组 Basic English 操作词","vs":"与 he 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"who\" / \"he\" 的替换练习"}]'),
  ('you', 'op', 59, 'OP', '你；你们；听话者', 'the person or people being spoken to', 'You may keep this book for a week.', '你可以把这本书保留一周。', '[{"w":"he","def":"he: 相关的动作或关系词","vs":"与 you 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"he\" / \"you\" 的替换练习"},{"w":"who","def":"who: 可帮助扩展句型的基础词","vs":"与 you 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"who\" / \"you\" 的替换练习"},{"w":"and","def":"and: 同一组 Basic English 操作词","vs":"与 you 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"and\" / \"you\" 的替换练习"}]'),
  ('who', 'op', 60, 'OP', '谁；……的人', 'ask or refer to a person', 'Who put the key under the stone?', '谁把钥匙放在石头下面？', '[{"w":"you","def":"you: 相关的动作或关系词","vs":"与 who 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"you\" / \"who\" 的替换练习"},{"w":"and","def":"and: 可帮助扩展句型的基础词","vs":"与 who 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"and\" / \"who\" 的替换练习"},{"w":"because","def":"because: 同一组 Basic English 操作词","vs":"与 who 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"because\" / \"who\" 的替换练习"}]');
